UPDATE MAIN_BANNER
SET DISPLAY_ORDER = DISPLAY_ORDER -1,
UPDATED_AT = SYSTIMESTAMP
WHERE BANNER_ID != #{bannerId}
AND DISPLAY_ORDER > #{oldDisplayOrder}
AND DISPLAY_ORDER  <=  #{newDisplayOrder}

UPDATE MAIN_BANNER
SET DISPLAY_ORDER = DISPLAY_ORDER +1,
UPDATED_AT = SYSTIMESTAMP
WHERE BANNER_ID != #{bannerId}
AND DISPLAY_ORDER >= #{newDisplayOrder}
AND DISPLAY_ORDER  <  #{oldDisplayOrder}
